"},{"role":"client","text":"Sendo que no ato da inscrição está assim: Pará pais, educadores,  alunos da FICV....","time":"12/02/2026 17:35:24"},{"role":"client","text":"Mas ja fiz a inscrição. Paguei 77","time":"12/02/2026 17:36:17"},{"role":"client","text":"Bom dia! Sobre o curso de Psicoteologia vai ter desconto quando terminar o ECC?","time":"13/02/2026 09:41:36"},{"role":"agent","text":"*Thayanne Sales:* A campanha de desconto dos cursos tem todos os meses, mas elas variam ","time":"13/02/2026 09:45:07","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 09:39:39"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 09:41:41"}]$tag$, $tag$2026-02-12 17:24:33+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 5, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
