ole":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/02/2026 09:45:49"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼","time":"13/02/2026 09:46:19","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia Thayanne","time":"13/02/2026 09:46:43"},{"role":"agent","text":"*Thayanne Sales:* A campanha de desconto dos cursos  variam de mês a mês","time":"13/02/2026 09:46:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Qual era o desconto que você tinha?","time":"13/02/2026 09:47:14","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Eu pagava um pouco mais de 90.00","time":"13/02/2026 09:48:18"},{"role":"agent","text":"*Thayanne Sales:* Esse desconto que seria de 70% não está mais ativo,  o máximo agora é de R$ 50% que as mensalidades ficam de R$ 179,68","time":"13/02/2026 09:49:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Poxa Thayanne com esse valor não consigo pagar","time":"13/02/2026 09:50:57"},{"role":"client","text":"Tive que trancar por motivos de saúde do meu pai, pois queria muito voltar, mais com esse valor fica inviável.","time":"13/02/2026 09:51:49"},{"role":"agent","text":"*Thayanne Sales:* Mas você pode preencher o requerimento solicitando mais desconto e a direção pode analisar ","time":"13/02/2026 09:51:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* https://bit.ly/RequerimentodeDescontoFICV]","time":"13/02/2026 09:51:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tem que enviar esses documentos","time":"13/02/2026 09:53:40"},{"role":"client","text":"Ou só enviar o email pedindo a solicitação","time":"13/02/2026 09:54:01"},{"role":"agent","text":"*Thayanne Sales:* sim","time":"13/02/2026 09:54:51","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 09:52:03"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 09:54:04"}]$tag$, $tag$2026-02-13 09:01:01+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 7, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$fa231448-1cbc-4391-8634-7850c86a3af0$tag$, $tag$2026021300030$tag$, $tag$Áxel Eduardo (5562983319159)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"13/02/2026 09:03:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom diaaa","time":"13/02/2026 09:13:55"},{"role":"client","text":"Tudo bem","time":"13/02/2026 09:13:58"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos que preencheu o formulário do Indique e ganhe ","time":"13/02/2026 09:14:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* E estamos entrando em contato para saber quem será o indicado ","time":"13/02/2026 09:15:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Na verdade eu fui indicado","time":"13/02/2026 09:18:47"},{"role":"agent","text":"*Thayanne Sales:* Ah ótimo","time":"13/02/2026 09:20:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* é que no formulário ficou faltando a informação de quem indicou","time":"13/02/2026 09:20:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"rol