INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e087e6d3-2294-41a3-8c9c-4f2130b007ff$tag$, $tag$2026021300037$tag$, $tag$Luana Oliveira (5586994686819)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Psicoteologia e quero mais informações.","time":"13/02/2026 09:26:02"},{"role":"client","text":"🌟 Bom dia Luana Oliveira! Que alegria ter você aqui com a gente! 🙌","time":"13/02/2026 09:26:03"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/02/2026 09:26:07"},{"role":"client","text":"Qual valor ?","time":"13/02/2026 09:26:08"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/02/2026 09:26:09"},{"role":"client","text":"E como funciona ?","time":"13/02/2026 09:26:10"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/02/2026 09:26:11"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"13/02/2026 09:26:17"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"13/02/2026 09:26:23"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"13/02/2026 09:26:23"},{"role":"client","text":"Sim, concordo","time":"13/02/2026 09:27:22"},{"role":"client","text":"✅ Obrigado, Luana Oliveira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"13/02/2026 09:27:23"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/02/2026 09:27:27"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/02/2026 09:27:53"},{"role":"client","text":"Olá! Luana Oliveira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/02/2026 09:27:54"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/02/2026 09:27:58"},{"role":"client","text":"Falar com um atendente","time":"13/02/2026 09:30:01"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"13/02/2026 09:30:02"},{"role":"client","text":"Valor dos cursos","time":"13/02/2026 09:30:42"},{"role":"client","text":"Quais cursos","time":"13/02/2026 09:30:47"},{"role":"client","text":"Como funciona as aulas","time":"13/02/2026 09:30:51"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/02/2026 09:37:34"},{"role":"client","text":"Olá","time":"13/02/2026 09:38:07"},{"role":"client","text":"Valor dos cursos","time":"13/02/2026 09:38:15"},{"role":"client","text":"Como funciona as aulas","time":"13/02/2026 09:38:17"},{"role":"client","text":"Quais cursos","time":"13/02/2026 09:38:18"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n******************\nDisciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão\n*********\nO valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\nEsse mês esta com condições especiais com 50% de desconto e as mensalidades ficam por R$ 243,50\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, *previsto para 30/03.\n","time":"13/02/2026 09:38:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"13/02/2026 16:31:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"13/02/2026 16:31:40","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?","time":"13/02/2026 16:32:08","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 09:36:23"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 09:38:25"}]$tag$, $tag$2026-02-13 09:26:02+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 4, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is