INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f115fa08-885b-4159-9e75-697f1cce3f71$tag$, $tag$2026021700028$tag$, $tag$David Paes (5583993150006)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"17/02/2026 14:49:56"},{"role":"client","text":"🌟 Boa tarde David Paes! Que alegria ter você aqui com a gente! 🙌","time":"17/02/2026 14:49:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"17/02/2026 14:50:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"17/02/2026 14:50:05"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"17/02/2026 14:50:12"},{"role":"client","text":"O link está informando que as inscrições estão encerradas","time":"17/02/2026 14:50:20"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"17/02/2026 14:50:21"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"17/02/2026 14:50:22"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"17/02/2026 14:50:41"},{"role":"client","text":"Olá! David Paes!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"17/02/2026 14:50:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"17/02/2026 14:50:46"},{"role":"client","text":"Saber sobre os cursos","time":"17/02/2026 14:51:00"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"17/02/2026 14:51:04"},{"role":"client","text":"Pós-Graduação","time":"17/02/2026 14:51:14"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"17/02/2026 14:51:18"},{"role":"client","text":"Novo Testamento","time":"17/02/2026 14:51:29"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"17/02/2026 14:51:30"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"17/02/2026 14:51:34"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"17/02/2026 14:51:47"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"17/02/2026 14:51:48"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"17/02/2026 14:51:48"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"19/02/2026 08:10:19"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"19/02/2026 08:10:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oi Thayanne","time":"19/02/2026 09:13:35"},{"role":"client","text":"Bom dia","time":"19/02/2026 09:13:42"},{"role":"client","text":"Sobre a pós de Novo Testamento","time":"19/02/2026 09:13:57"},{"role":"client","text":"Fui tentar a matrícula e apareceu que já estava esgotado","time":"19/02/2026 09:15:15"},{"role":"agent","text":"*Thayanne Sales:* Mudamos de sistema e de  link de inscrição pode ter sido isso","time":"19/02/2026 09:18:23","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"19/02/2026 09:18:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"19/02/2026 09:18:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. \n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"19/02/2026 09:18:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas  R$ 179,68\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"19/02/2026 09:18:58","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Perfeito","time":"19/02/2026 09:35:33"},{"role":"client","text":"Vamos prosseguir","time":"19/02/2026 09:35:40"},{"role":"agent","text":"*Thayanne Sales:* Que ótimo, você vai fazer a inscrição e finalizar. Assim que finalizar