INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$25406a75-a973-4325-ae53-d36b3806544f$tag$, $tag$2026021300092$tag$, $tag$Marina Granzoto Silva (5581999677571)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"13/02/2026 13:52:05"},{"role":"client","text":"🌟 Boa tarde Marina Granzoto Silva! Que alegria ter você aqui com a gente! 🙌","time":"13/02/2026 13:52:06"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/02/2026 13:52:10"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/02/2026 13:52:14"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/02/2026 13:52:21"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/02/2026 13:52:34"},{"role":"client","text":"Olá! Marina Granzoto Silva!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/02/2026 13:52:35"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/02/2026 13:52:39"},{"role":"client","text":"Falar com um atendente","time":"13/02/2026 13:52:55"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"13/02/2026 13:52:56"},{"role":"client","text":"Gostaria de saber se está tudo certo com o meu pagamento desde mês.  E se ainda terei mais parcelas para pegar nos próximos meses.","time":"13/02/2026 13:54:14"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/02/2026 14:02:24"},{"role":"agent","text":"*Thayanne Sales:* Me envia seu nome completo que vou verificar","time":"13/02/2026 14:02:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Marina Granzoto Silva","time":"13/02/2026 14:03:00"},{"role":"agent","text":"*Thayanne Sales:* Está tudo certo com a sua matricula","time":"13/02/2026 14:06:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* O boleto do próximo mês chega no seu e-mail 10 dias antes do vencimento","time":"13/02/2026 14:07:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"13/02/2026 14:07:36","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Somente isso. Muito obrigada 🤗","time":"13/02/2026 14:07:54"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo final de semana. ","time":"13/02/2026 14:11:59","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 14:05:56"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 14:07:57"}]$tag$, $tag$2026-02-13 13:52:05+00$tag$, FALSE, FALSE, 7.6, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 7, 2, 9, 5, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, cre