INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1570a264-010c-41fc-af90-5307b1ef8e45$tag$, $tag$2026021300095$tag$, $tag$Carlos Alberto (5581997125036)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde me chamo Thayanne Sales da Cidade Viva! \n","time":"13/02/2026 14:19:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Boa tarde","time":"13/02/2026 14:27:54"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu pedido de desconto via requerimento e venho da boas noticias, foi liberado para você o desconto de 30% em todo o curso de  graduação Teologia EAD e a matricula por R$ 99,00.\n\nVamos prosseguir com a sua matricula?","time":"13/02/2026 14:30:53","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Boa tarde , a Paz minha irmã 🙌🏻","time":"13/02/2026 14:31:28"},{"role":"client","text":"No caso , qual valor ficaria as  parcelas ?","time":"13/02/2026 14:32:02"},{"role":"agent","text":"*Thayanne Sales:* De  R$ 479,64 por R$ 335,74","time":"13/02/2026 14:36:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"A mensalidade não é 399,00 ?","time":"13/02/2026 14:38:37"},{"role":"client","text":"Um casal amigo aqui da igreja , conseguiu 40% \nA mensalidade deles ficou em 239,00","time":"13/02/2026 14:39:56"},{"role":"client","text":"Era esse valor que eu estava tentando","time":"13/02/2026 14:40:13"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698f624e20ee77783808c360)","time":"13/02/2026 14:41:34"},{"role":"agent","text":"*Thayanne Sales:* É possível fazer a matricula até março para esse semestre mas o valor mensal pode variar de acordo com a data de matrícula.\n\nFazendo a matricula em janeiro é possível parcelar o semestre em 6 x\nFazendo a matricula em Fevereiro é possível parcelar o semestre em 5 x\nFazendo a matricula em Março é possível parcelar o semestre em 4 x","time":"13/02/2026 14:46:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor total do semestre é o mesmo que muda é o parcelamento","time":"13/02/2026 14:47:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* No próximo semestre se fazer a rematrícula em junho é possível parcelar em 6x 279,79","time":"13/02/2026 14:48:43","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Ok , vou analisar","time":"13/02/2026 14:49:20"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 14:47:23"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 14:49:25"}]$tag$, $tag$2026-02-13 14:19:53+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED