INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c701124f-8e62-44f7-a0d4-878f8e40e32d$tag$, $tag$2026021300099$tag$, $tag$Granjeando Talentos (5521966990479)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde.\n\nGostaria de informações sobre o curso de Psicopedagogia.","time":"13/02/2026 14:40:43"},{"role":"client","text":"🌟 Boa tarde Granjeando Talentos! Que alegria ter você aqui com a gente! 🙌","time":"13/02/2026 14:40:44"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/02/2026 14:40:48"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/02/2026 14:40:52"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/02/2026 14:40:56"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"13/02/2026 14:41:02"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"13/02/2026 14:41:08"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"13/02/2026 14:41:09"},{"role":"client","text":"Sim, concordo","time":"13/02/2026 14:41:24"},{"role":"client","text":"✅ Obrigado, Granjeando Talentos! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"13/02/2026 14:41:25"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/02/2026 14:41:29"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/02/2026 14:41:46"},{"role":"client","text":"Olá! Granjeando Talentos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/02/2026 14:41:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/02/2026 14:41:51"},{"role":"client","text":"Saber sobre os cursos","time":"13/02/2026 14:42:05"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"13/02/2026 14:42:10"},{"role":"client","text":"Pós-Graduação","time":"13/02/2026 14:42:20"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"13/02/2026 14:42:24"},{"role":"client","text":"Psicopedagogia","time":"13/02/2026 14:42:45"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"13/02/2026 14:42:46"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"13/02/2026 14:42:50"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"13/02/2026 14:43:09"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"13/02/2026 14:43:10"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/02/2026 14:57:21"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"13/02/2026 14:57:49","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"13/02/2026 14:57:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira","time":"13/02/2026 14:58:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Psicopedagogia  está em 18 mensalidades de *R$ 479,16*.\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"13/02/2026 14:58:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58.\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"13/02/2026 14:58:41","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 14:41:12"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 14:43:18"}]$tag$, $tag$2026-02-13 14:40:43+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 5, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
