INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$43f12316-378a-47c8-8f28-b76120d4a7e9$tag$, $tag$2026021600013$tag$, $tag$Simone Dilda Rovani (5549999295355)$tag$, NULL, $tag$Carlos Kleber$tag$, $tag$[{"role":"client","text":"Bom dia","time":"16/02/2026 10:21:05"},{"role":"client","text":"🌟 Bom dia Simone Dilda Rovani! Que alegria ter você aqui com a gente! 🙌","time":"16/02/2026 10:21:06"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"16/02/2026 10:21:10"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"16/02/2026 10:21:14"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"16/02/2026 10:21:21"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"16/02/2026 10:21:34"},{"role":"client","text":"Olá! Simone Dilda Rovani!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"16/02/2026 10:21:35"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"16/02/2026 10:21:39"},{"role":"client","text":"Falar com um atendente","time":"16/02/2026 10:21:53"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"16/02/2026 10:21:54"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"16/02/2026 10:21:55"},{"role":"client","text":"Me chamo Simone \nSou aluna da pós em educação clássica cristã.\nMinha nota de participação no fórum não apareceu em minha média na matéria de história a educação clássica cristã.","time":"16/02/2026 10:23:35"},{"role":"client","text":"Boa tarde","time":"17/02/2026 14:50:11"},{"role":"client","text":"Boa tarde","time":"17/02/2026 14:56:43"},{"role":"client","text":"Me chamo Simone Dilda Rovani, sou aluna da pós em educação cristã clássica.\nA nota de participação no fórum não apareceu em minha média, matéria de história a educação clássica cristã.\n\nAguardo considerações.\n\nAtt,\nSimone Dilda Rovani\n(49)99929-5355","time":"17/02/2026 15:05:01"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6995f14e7cff9eb76603e0ff) | Boa tarde! Minha nota no fórum não aparece. Gostaria de um retorno quanto a isso.\nAguardo","time":"18/02/2026 14:05:18"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6995f1beec8aa2abf104a973) | Boa tarde! Minha nota no fórum não aparece. Gostaria de um retorno quanto a isso.\nAguardo","time":"18/02/2026 14:07:10"},{"role":"client","text":"Thayanne Sales transferiu o atendimento para a equipe FICV - PÓS EDUCAÇÃO CRISTÃ CLASSICA","time":"19/02/2026 08:03:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Carlos Kleber","time":"19/02/2026 09:30:58"},{"role":"agent","text":"*Carlos Kleber:* Bom dia. Você é de qual turma? Se estiver se referindo à disciplina 4, História da Educação Clássica, atribui nota hoje. Confere, por favor.","time":"19/02/2026 09:31:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom Dia Carlos, tudo bem? \nNão sei dizer qual turma sou.\nMas apenas a nota do fórum não consta em minha média. Nas outras disciplinas não demorou para concluir a nota.","time":"19/02/2026 09:33:34"},{"role":"client","text":"Me chamo Simone Dilda Rovani","time":"19/02/2026 09:33:50"},{"role":"agent","text":"*Carlos Kleber:* A disciplina foi a História da Educação?","time":"19/02/2026 09:34:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim","time":"19/02/2026 09:44:38"},{"role":"agent","text":"*Carlos Kleber:* Já corrigi. Confere, por favor.","time":"19/02/2026 09:48:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok Carlos. Apareceu.\nMuito obrigada \nDeus abençoe","time":"19/02/2026 09:51:55"},{"role":"agent","text":"*Carlos Kleber:* Certo. Se precisar, é só chamar. Que Deus abençoe sua vida.","time":"19/02/2026 09:54:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Amém \nObrigada","time":"19/02/2026 09:58:00"},{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"20/02/2026 11:15:25"},{"role":"agent","text":"*Carlos Kleber:* Não entendi. Quer fazer a graduação?","time":"20/02/2026 11:16:52","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá, sim. Tenho interesse","time":"20/02/2026 11:18:48"},{"role":"agent","text":"*Carlos Kleber:* Então, vou passar seu atendimento.","time":"20/02/2026 11:20:02","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Carlos Kleber transferiu o atendimento para a equipe FICV - SECRETARIA","time":"20/02/2026 11:20:21"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"20/02/2026 13:49:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/02/2026 14:06:25"},{"role":"client","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n","time":"20/02/2026 18:38:39"},{"role":"client","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉 \n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/02/2026 18:39:05"},{"role":"client","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 18:39:25"},{"role":"client","text":"*Karina Pimentel:* Qualquer duvida estamos a disposição!","time":"20/02/2026 18:39:43"},{"role":"client","text":"Atendimento Finalizado!\n\nSimone Dilda Rovani, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 18:39:46"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 18:39:47"},{"role":"client","text":"Simone Dilda Rovani, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 18:54:47"}]$tag$, $tag$2026-02-16 10:21:05+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5a5fd609-70b0-4d1c-a8c8-8f98abfe38eb$tag$, $tag$2026021600014$tag$, $tag$Leandro Alfredo (5583988462713)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"16/02/2026 10:54:30"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"16/02/2026 10:54:31"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"16/02/2026 10:54:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"19/02/2026 08:07:04"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"19/02/2026 08:07:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"19/02/2026 09:27:34"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"19/02/2026 09:28:18","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"19/02/2026 09:28:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"19/02/2026 09:28:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.689,54. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 675,81.\n\n✨Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"19/02/2026 09:28:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"19/02/2026 09:28:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia","time":"19/02/2026 10:21:16"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/69970eecd85b660914031f58)","time":"19/02/2026 10:23:56"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/69970eecc9208a23620ad13b)","time":"19/02/2026 10:23:56"},{"role":"client","text":"Consigo entrar em qual turma ?","time":"19/02/2026 10:23:58"},{"role":"agent","text":"*Thayanne Sales:*  📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"19/02/2026 10:24:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ja posso mandar agora ou so depois que eu ja for aluno matriculado","time":"19/02/2026 10:26:04"},{"role":"client","text":"?","time":"19/02/2026 10:26:15"},{"role":"agent","text":"*Thayanne Sales:* Pode enviar por e-mail","time":"19/02/2026 10:28:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok vou fazer","time":"19/02/2026 10:29:04"},{"role":"client","text":"Dependendo da resposta faço a matrícula","time":"19/02/2026 10:29:14"},{"role":"client","text":"Obrigado","time":"19/02/2026 10:29:18"},{"role":"client","text":"🙏","time":"19/02/2026 10:29:21"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"19/02/2026 10:32:20","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nLeandro Alfredo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/02/2026 10:32:25"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"22/02/2026 10:27:23"},{"role":"client","text":"Sua sessão expirou!","time":"22/02/2026 10:29:25"}]$tag$, $tag$2026-02-16 10:54:30+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 9, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, dept