:52"}]$tag$, $tag$2026-02-17 12:49:39+00$tag$, FALSE, FALSE, 6.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 7, 10, 3, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$20c9bd64-25b5-476a-a323-48b61e1231b1$tag$, $tag$2026021800012$tag$, $tag$Marcelly Elias (5583986414112)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"18/02/2026 08:44:51"},{"role":"client","text":"🌟 Bom dia Marcelly Elias! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 08:44:52"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 08:44:57"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 08:45:01"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"18/02/2026 08:45:05"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"18/02/2026 08:45:10"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"18/02/2026 08:45:16"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"18/02/2026 08:45:17"},{"role":"client","text":"Sim, concordo","time":"18/02/2026 08:45:28"},{"role":"client","text":"✅ Obrigado, Marcelly Elias! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"18/02/2026 08:45:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 08:45:32"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 08:45:46"},{"role":"client","text":"Olá! Marcelly Elias!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 08:45:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 08:45:51"},{"role":"client","text":"Falar com um atendente","time":"18/02/2026 08:46:03"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"18/02/2026 08:46:04"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 08:46:05"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:19:49"},{"role":"client","text":"Qual o valor da faculdade de teologia ?","time":"19/02/2026 12:44:35"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"20/02/2026 08:25:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉 \n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/02/2026 08:26:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nMarcelly Elias, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 18:16:40"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 18:16:41"},{"role":"client","text":"Marcelly Elias, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 18:31:42"}]$tag$, $tag$2026-02-18 08:44:51+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 2, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f70a78b8-ce34-4168-a97a-c5b2bec730f5$tag$, $tag$2026021800019$tag$, $tag$Kelly Cristina Fazio (5519987300731)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"18/02/2026 09:34:40"},{"role":"client","text":"🌟 Bom dia Kelly Cristina Fazio! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 09:34:41"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 09:34:44"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 09:34:48"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 09:34:55"},{"role":"client","text":"Eventos e locações","time":"18/02/2026 09:35:09"},{"role":"client","text":"🌱 Cada evento é uma semente\nKelly Cristina Fazio, aqui na Cidade Viva, acreditamos que cada evento realizado é mais do que uma atividade — é uma semente plantada.\n\nUma semente que transforma vidas, fortalece a comunidade e mantém viva a missão que nos move. 💛\n\nPor isso, estamos aqui para te ajudar a planejar e realizar o seu evento com cuidado, excelência e propósito.","time":"18/02/2026 09:35:10"},{"role":"client","text":"Vamos dar continuidade ao seu atendimento? \n\nÓtimo, Kelly Cristina Fazio! Para que possamos te ajudar da melhor forma, escolha uma das opções abaixo digitando o número correspondente:","time":"18/02/2026 09:35:15"},{"role":"client","text":"Voltar ao menu anterior \n Voltar ao menu anterior","time":"18/02/2026 09:35:34"},{"role":"client","text":"Ótimo! Por favor, selecione abaixo a opção que deseja ter mais informações sobre:","time":"18/02/2026 09:35:35"},{"role":"client","text":"Voltar ao menu principal","time":"18/02/2026 09:35:47"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 09:35:48"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 09:36:07"},{"role":"client","text":"Olá! Kelly Cristina Fazio!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 09:36:09"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 09:36:14"},{"role":"client","text":"Falar com um atendente","time":"18/02/2026 09:36:30"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"18/02/2026 09:36:32"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 09:36:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:20:15"},{"role":"client","text":"Oi, Karina. Bom dia!","time":"19/02/2026 09:53:39"},{"role":"agent","text":"*Karina Pimentel:* Seria sobre locações? ","time":"19/02/2026 09:54:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Oi, Karina. Bom dia!","time":"19/02/2026 09:59:10"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"19/02/2026 09:59:23","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"client","text":"Não. Eu selecionei essa opção indevidamente, mas depois voltei ao menu principal para selecionar faculdade.","time":"19/02/2026 09:59:50"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"19/02/2026 10:01:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Fiz minha matrícula no dia 5/02 para o curso de Educação Clássica Cristã e queria saber quando receberei o acesso para a plataforma das aulas. Se isso será próximo à abril, quando o curso tem previsão de início ou antes.","time":"19/02/2026 10:01:41"},{"role":"agent","text":"*Karina Pimentel:* Como podemos lhe ajudar?","time":"19/02/2026 10:01:46","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"19/02/2026 10:01:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Será enviado o seu acesso no mês de Abril, na semana de inicio do curso!","time":"19/02/2026 10:02:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok. Tenho outra dúvida, mas sobre o Congresso de Educação Clássica Cristã que acontecerá em São Paulo. Consigo tratar sobre este evento por aqui também?","time":"19/02/2026 10:03:29"},{"role":"agent","text":"*Karina Pimentel:* Sim, o que seria senhora Kelly?","time":"19/02/2026 10:12:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Fiz minha inscrição pelo Instagram e nas instruções da inscrição há a informação de que seria concedido o acesso às palestras do congresso anterior, mas não o recebi.","time":"19/02/2026 10:31:59"},{"role":"agent","text":"*Karina Pimentel:* Ainda esta semana, o acesso às palestras do Congresso passado será enviado no e-mail de cadastro.","time":"19/02/2026 11:18:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Muito obrigada!","time":"19/02/2026 11:23:00"},{"role":"agent","text":"*Karina Pimentel:* De nada!","time":"19/02/2026 11:42:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"19/02/2026 11:42:52","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nKelly Cristina Fazio, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/02/2026 11:42:55"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/02/2026 11:42:56"},{"role":"client","text":"Kelly Cristina Fazio, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"19/02/2026 11:57:56"}]$tag$, $tag$2026-02-18 09:34:40+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0d5bb3f1-24b4-407c-8694-15900a213784$tag$, $tag$2026021800020$tag$, $tag$Tamara Defanti (5547991333006)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá","time":"18/02/2026 09:37:10"},{"role":"client","text":"🌟 Bom dia Tamara Defanti! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 09:37:12"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 09:37:16"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 09:37:20"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 09:37:28"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 09:38:10"},{"role":"client","text":"Olá! Tamara Defanti!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 09:38:11"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 09:38:15"},{"role":"client","text":"Outros assuntos","time":"18/02/2026 09:38:44"},{"role":"client","text":"Sem problemas!\n\nMe conta aqui com o que você precisa de ajuda, e vou te direcionar para o melhor caminho.\n","time":"18/02/2026 09:38:45"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 09:38:46"},{"role":"client","text":"Estou sem nota do fórum da última disciplina. Por gentileza vocês podem avaliar isso, pois aparece como reprovado, porém eu fiz todas as etapas..","time":"18/02/2026 09:40:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:20:18"},{"role":"client","text":"Olá","time":"19/02/2026 10:12:57"},{"role":"client","text":"A nota do fórum não foi computada","time":"19/02/2026 10:13:08"},{"role":"client","text":"E apare o como reprovada na última matéria por falta dessa nota","time":"19/02/2026 10:13:25"},{"role":"client","text":"Agora atualizei a página, computaram 🤪","time":"19/02/2026 10:14:24"},{"role":"client","text":"😳","time":"19/02/2026 10:14:53"},{"role":"client","text":"Obrigada","time":"19/02/2026 10:14:55"},{"role":"agent","text":"*Karina Pimentel:* Maravilha!","time":"19/02/2026 10:15:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"19/02/2026 10:15:15","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nTamara Defanti, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/02/2026 10:15:18"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/02/2026 10:15:20"},{"role":"client","text":"Tamara Defanti, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"19/02/2026 10:30:21"}]$tag$, $tag$2026-02-18 09:37:10+00$tag$, FALSE, FALSE, 6.8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 3, 2, 9, 2, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2a2fe490-70f2-4cc9-a078-0a781fef3633$tag$, $tag$2026021800023$tag$, $tag$Léia Marelisia do Nascimento Henrique (5511952045329)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oiee","time":"18/02/2026 10:02:31"},{"role":"client","text":"🌟 Bom dia LÃ©ia Henrique! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 10:02:31"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 10:02:36"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 10:02:40"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 10:02:47"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 10:03:03"},{"role":"client","text":"Olá! LÃ©ia Henrique!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 10:03:05"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 10:03:09"},{"role":"client","text":"Saber sobre os cursos","time":"18/02/2026 10:03:26"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"18/02/2026 10:03:30"},{"role":"client","text":"Pós-Graduação","time":"18/02/2026 10:03:42"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"18/02/2026 10:03:45"},{"role":"client","text":"Psicopedagogia","time":"18/02/2026 10:04:08"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"18/02/2026 10:04:09"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"18/02/2026 10:04:13"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"18/02/2026 10:04:27"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"18/02/2026 10:04:28"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 10:04:28"},{"role":"client","text":"Ok","time":"18/02/2026 10:13:31"},{"role":"client","text":"Olá","time":"18/02/2026 14:52:21"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:20:24"},{"role":"client","text":"Oie","time":"19/02/2026 08:29:57"},{"role":"client","text":"Bom dia","time":"19/02/2026 08:29:59"},{"role":"client","text":"Tudo bem?","time":"19/02/2026 08:30:04"},{"role":"client","text":"Gostaria de tirar uma dúvida sobre o grade do curso de psicopedagogia","time":"19/02/2026 08:30:28"},{"role":"agent","text":"*Karina Pimentel:* *Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira\n","time":"19/02/2026 09:44:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obrigada","time":"19/02/2026 10:23:23"},{"role":"client","text":"Esse curso tem estágio né?","time":"19/02/2026 10:23:32"},{"role":"client","text":"Como ele é online, como funcionaria o estágio?","time":"19/02/2026 10:23:45"},{"role":"agent","text":"*Karina Pimentel:* * PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA *\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"19/02/2026 10:26:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69971145426b6d3fc408a7a4)","time":"19/02/2026 10:33:57"},{"role":"client","text":"É que li aqui sobre o estágio","time":"19/02/2026 10:34:02"},{"role":"client","text":"Mas então não é necessário?","time":"19/02/2026 10:34:11"},{"role":"client","text":"Eu me matriculei no curso  de gestão escolar, mas vi grade desse de psicopedagogia e quero saber é possível trocar?","time":"19/02/2026 10:35:03"},{"role":"client","text":"Mesmo que houver alteração no valor da mensalidade","time":"19/02/2026 10:35:12"},{"role":"client","text":"Dependendo desse valor, mudaria. Achei que tem muito mais o meu perfil","time":"19/02/2026 10:35:33"},{"role":"client","text":"Como as aulas não iniciaram ainda, seria possível essa mudança?","time":"19/02/2026 10:35:48"},{"role":"agent","text":"*Karina Pimentel:* Não!","time":"19/02/2026 10:39:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe transferir na Secretaria ok! Eles verificam as possibilidades ok!","time":"19/02/2026 10:39:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok. Mas isso talvez não afete um pouco na prática? É que tenho um pouco de receio, na parte clínica","time":"19/02/2026 10:40:44"},{"role":"client","text":"Última dúvida, se não tem o estágio e é online, como é a interação com o professor no caso de uma dúvida mais pontual?","time":"19/02/2026 10:41:34"},{"role":"client","text":"Tá ótimo 😍","time":"19/02/2026 10:41:44"},{"role":"agent","text":"*Karina Pimentel:* 😉","time":"19/02/2026 10:45:00","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"19/02/2026 10:45:09"},{"role":"client","text":"Oká","time":"19/02/2026 11:05:08"},{"role":"client","text":"Olá","time":"19/02/2026 11:05:10"},{"role":"client","text":"Tudo bem? Daqui a pouco irei estar no trabalho e não poderei interagir muito.\n\nMas gostaria de saber se existe a possibilidade de mudar de curso?","time":"19/02/2026 11:47:20"},{"role":"client","text":"Me matriculei no curso de gestão escolar e gostei muito da grade","time":"19/02/2026 11:47:38"},{"role":"client","text":"Mas ontem e hoje tive acesso a grade da pós de psicopedagogia e achei que tem muito mais a ver comigo ☺️","time":"19/02/2026 11:48:03"},{"role":"client","text":"Como ambos os cursos ainda não iniciaram daria pra trocar? Eu já paguei a matrícula do curso de gestão. Mas se houver qualquer possibilidade me avise. Gostaria muito de trocar","time":"19/02/2026 11:48:49"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"19/02/2026 15:42:51"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"19/02/2026 15:53:03"},{"role":"client","text":"*Thayanne Sales:* Me envia seu nome completo","time":"19/02/2026 15:53:19"},{"role":"client","text":"Léia Marelisia do Nascimento Henrique","time":"19/02/2026 16:10:14"},{"role":"client","text":"*Thayanne Sales:* Olá bom dia!","time":"20/02/2026 08:46:36"},{"role":"client","text":"*Thayanne Sales:* Passando para avisar que foi efetuada a troca de curso.","time":"20/02/2026 08:47:07"},{"role":"client","text":"Olá","time":"20/02/2026 08:47:27"},{"role":"client","text":"🥳🥳🥳🥳","time":"20/02/2026 08:47:33"},{"role":"client","text":"*Thayanne Sales:* Mas só lembrando que Psicopedagogia são 18 meses e gestão era 16. Então vai ter a diferença de 2 meses em mensalidade e conteúdo. ","time":"20/02/2026 08:47:52"},{"role":"client","text":"*Thayanne Sales:* Agora é só aguardar o inicio das aulas em abril, o link de acesso será enviado para você por e-mail em abril.","time":"20/02/2026 08:48:10"},{"role":"client","text":"Você só poderia me informar sobre a data de início desse curso e sobre a mensalidade? A forma de pagamento e valor das mensalidades mudam?","time":"20/02/2026 08:48:10"},{"role":"client","text":"Ok. Sem problemas quanto a isso!","time":"20/02/2026 08:48:41"},{"role":"client","text":"*Thayanne Sales:* Os valores são os mesmos ","time":"20/02/2026 08:48:59"},{"role":"client","text":"*Thayanne Sales:* Iniciará em abril até o dia 10, só a data que não foi confirmada ainda. ","time":"20/02/2026 08:49:27"},{"role":"client","text":"*Thayanne Sales:* E todos os meses o boleto vai para o seu e-mail 10 dias antes do vencimento","time":"20/02/2026 08:49:45"},{"role":"client","text":"Ok","time":"20/02/2026 08:50:10"},{"role":"client","text":"Obrigada","time":"20/02/2026 08:50:12"},{"role":"client","text":"*Thayanne Sales:* E você vai receber o acesso para o portal do aluno que também conseguirá verificar os boletos por lá.","time":"20/02/2026 08:50:12"},{"role":"client","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"20/02/2026 08:50:21"},{"role":"client","text":"O acesso ainda não veio né?","time":"20/02/2026 08:50:40"},{"role":"client","text":"Não, ficou tudo claro!","time":"20/02/2026 08:50:50"},{"role":"client","text":"*Thayanne Sales:* O acesso só será enviado em abril","time":"20/02/2026 08:53:01"},{"role":"client","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo final de semana. ","time":"20/02/2026 08:53:18"},{"role":"client","text":"Atendimento Finalizado!\n\nLéia Marelisia do Nascimento Henrique, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 08:53:22"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 08:53:23"},{"role":"client","text":"Léia Marelisia do Nascimento Henrique, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 09:08:24"}]$tag$, $tag$2026-02-18 10:02:31+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 17, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4eab568b-266c-4ea9-b11b-037e3c3eba83$tag$, $tag$2026021800026$tag$, $tag$Fabiana P M Bachmann (5541985118751)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia, aguardo retorno.","time":"18/02/2026 10:21:58"},{"role":"client","text":"🌟 Bom dia Fabiana P M Bachmann! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 10:21:59"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 10:22:03"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 10:22:07"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"18/02/2026 10:22:11"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"18/02/2026 10:22:17"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"18/02/2026 10:22:23"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"18/02/2026 10:22:24"},{"role":"client","text":"Sim, concordo","time":"18/02/2026 10:23:06"},{"role":"client","text":"✅ Obrigado, Fabiana P M Bachmann! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"18/02/2026 10:23:07"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 10:23:10"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 10:23:28"},{"role":"client","text":"Olá! Fabiana P M Bachmann!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 10:23:29"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 10:23:33"},{"role":"client","text":"Saber sobre os cursos","time":"18/02/2026 10:23:48"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"18/02/2026 10:23:52"},{"role":"client","text":"Graduação","time":"18/02/2026 10:24:11"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"18/02/2026 10:24:15"},{"role":"client","text":"Teologia (EAD)","time":"18/02/2026 10:24:30"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"18/02/2026 10:24:31"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"18/02/2026 10:24:35"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"18/02/2026 10:25:08"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"18/02/2026 10:25:09"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 10:25:10"},{"role":"client","text":"Estou no aguardo","time":"18/02/2026 13:24:47"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:20:30"},{"role":"client","text":"Bom dia karina","time":"19/02/2026 08:21:02"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"19/02/2026 08:36:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/02/2026 08:37:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok, muito obrigada! Preciso fazer uns cálculos com Deus e pedir o milagre!! Agora é correr em busca do sonho.","time":"19/02/2026 09:19:43"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"19/02/2026 09:23:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Se desejar temos o requerimento de descontos ok!","time":"19/02/2026 09:23:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* https://bit.ly/RequerimentodeDescontoFICV","time":"19/02/2026 09:24:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Vou dar uma olhada tb,obg!","time":"19/02/2026 09:28:44"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!\nQualquer duvida estamos a disposição!\nDeus abençoe! ","time":"20/02/2026 08:46:02","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nFabiana P M Bachmann, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 08:46:05"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 08:46:07"},{"role":"client","text":"Fabiana P M Bachmann, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 09:01:10"}]$tag$, $tag$2026-02-18 10:21:58+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
