INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$08e98b21-ab74-46c2-8dcd-73cc7e937405$tag$, $tag$2026021800040$tag$, $tag$Glauco Querino (5562999913210)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá bom dia! O vencimento da matricula é hoje, porém preciso alinhar a questão dos valores, pois no contrato não tem a questão que passou acima sobre o desconto de 50%.","time":"18/02/2026 11:21:50"},{"role":"client","text":"🌟 Bom dia Glauco Querino! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 11:21:51"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 11:21:55"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 11:21:58"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 11:22:05"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 11:22:17"},{"role":"client","text":"Olá! Glauco Querino!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 11:22:18"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 11:22:22"},{"role":"client","text":"Saber sobre os cursos","time":"18/02/2026 11:22:32"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"18/02/2026 11:22:36"},{"role":"client","text":"Pós-Graduação","time":"18/02/2026 11:22:45"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"18/02/2026 11:22:49"},{"role":"client","text":"