INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4c00d8b4-4513-4fef-8dde-839eb714fe1a$tag$, $tag$2026021800049$tag$, $tag$Maíra Meira (5511950327979)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia! Tudo bem? Estou aguardando uma resposta de como posso acessar ao congresso do ano passado","time":"18/02/2026 12:17:56"},{"role":"client","text":"🌟 Boa tarde Maíra Meira! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 12:17:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 12:18:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 12:18:05"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 12:18:12"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 12:20:27"},{"role":"client","text":"Olá! Maíra Meira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 12:20:28"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 12:20:33"},{"role":"client","text":"Falar com um atendente","time":"18/02/2026 12:20:46"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"18/02/2026 12:20:47"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 12:20:48"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 08:21:08"},{"role":"client","text":"Olá Karina, tudo bem?","time":"19/02/2026 08:27:54"},{"role":"client","text":"Eu comprei o segundo lote do segundo congresso q terá e gostaria de saber como faço para ter acesso as palestras do primeiro congresso, que estava como bônus. Gostaria mto de poder ver.","time":"19/02/2026 08:29:05"},{"role":"agent","text":"*Karina Pimentel:* Ainda esta semana, o acesso às palestras do Congresso passado será enviado no e-mail de cadastro.","time":"19/02/2026 11:19:07","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nMaíra Meira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 08:53:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 08:53:18"},{"role":"client","text":"Maíra Meira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 09:08:18"}]$tag$, $tag$2026-02-18 12:17:56+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_