INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d702ad14-2db3-4d99-af92-2c14d2ec43ce$tag$, $tag$2026021800075$tag$, $tag$JOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR (5598984328008)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"18/02/2026 16:04:04"},{"role":"client","text":"🌟 Boa tarde JOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR! Que alegria ter você aqui com a gente! 🙌","time":"18/02/2026 16:04:05"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"18/02/2026 16:04:09"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"18/02/2026 16:04:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"18/02/2026 16:04:18"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"18/02/2026 16:04:24"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"18/02/2026 16:04:29"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"18/02/2026 16:04:30"},{"role":"client","text":"Sim, concordo","time":"18/02/2026 16:04:42"},{"role":"client","text":"✅ Obrigado, JOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"18/02/2026 16:04:43"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"18/02/2026 16:04:47"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"18/02/2026 16:06:15"},{"role":"client","text":"Olá! JOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"18/02/2026 16:06:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"18/02/2026 16:06:20"},{"role":"client","text":"Saber sobre os cursos","time":"18/02/2026 16:07:00"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"18/02/2026 16:07:05"},{"role":"client","text":"Pós-Graduação","time":"18/02/2026 16:07:18"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"18/02/2026 16:07:22"},{"role":"client","text":"Novo Testamento","time":"18/02/2026 16:07:42"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"18/02/2026 16:07:43"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"18/02/2026 16:07:47"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"18/02/2026 16:08:44"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"18/02/2026 16:08:45"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"18/02/2026 16:08:46"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"19/02/2026 08:41:37"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"19/02/2026 08:41:44","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n*************************","time":"19/02/2026 08:41:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"19/02/2026 08:42:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. \n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"19/02/2026 08:42:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas  R$ 179,68\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"19/02/2026 08:42:24","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"SIM","time":"19/02/2026 08:51:19"},{"role":"agent","text":"*Thayanne Sales:* Que maravilha ","time":"19/02/2026 08:58:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Faça sua inscrição por esse link, assim que concluir me avise que aplico o desconto","time":"19/02/2026 08:58:59","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"20/02/2026 08:09:37","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nJOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 08:53:33"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 08:53:34"},{"role":"client","text":"JOSE CLAUDIO DOS SANTOS JUNIOR JUNIOR, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/02/2026 09:08:35"}]$tag$, $tag$2026-02-18 16:04:04+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 8, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$app