INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0ee0432e-59e2-4072-aecd-3fe304aa9515$tag$, $tag$2026021900023$tag$, $tag$Osmar Stefano Menna Barreto (5561984834327)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"19/02/2026 09:12:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"19/02/2026 09:13:51"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nVocê foi indicado por um amigo (Samuel Menna) e ele nos informou  o seu interesse pelo nosso curso de Graduação em Teologia EAD  e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\n\nPodemos conversar agora?","time":"19/02/2026 09:17:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim","time":"19/02/2026 09:17:47"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6996ffbd857e1333a40cc274)","time":"19/02/2026 09:19:09"},{"role":"agent","text":"*Thayanne Sales:* Posso lhe enviar as informações e depois você ler com calma?","time":"19/02/2026 09:20:44","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Pode sim, por favor","time":"19/02/2026 11:02:43"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/02/2026 11:10:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"19/02/2026 11:10:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/02/2026 11:10:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.\n","time":"19/02/2026 11:10:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"20/02/2026 08:10:04","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6998469f2e25675b1202abb2)","time":"20/02/2026 08:33:52"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6998497339ad428a4f0f29f4)","time":"20/02/2026 08:45:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69987292e12a8806420ea64d)","time":"20/02/2026 11:41:22"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69987428f1ae6adb1e0931c2)","time":"20/02/2026 11:48:08"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69987432907228c9980f6041)","time":"20/02/2026 11:48:18"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6998963d2c784a99e9088c91)","time":"20/02/2